// Space: O(h)

/**
 * Definition for a binary tree node.
 * struct TreeNode {
 *     int val;
 *     TreeNode *left;
 *     TreeNode *right;
 *     TreeNode(int x) : val(x), left(NULL), right(NULL) {}
 * };
 */
class Solution {
public:
    TreeNode* convertBST(TreeNode* root) {
        int cur_sum = 0;
        convertBSTHelper(root, &cur_sum);
        return root;
    }

private:
    void convertBSTHelper(TreeNode* root, int *cur_sum) {
        if (!root) {
            return;
        }

        if (root->right) {
            convertBSTHelper(root->right, cur_sum);
        }
        root->val = (*cur_sum += root->val);
        if (root->left) {
            convertBSTHelper(root->left, cur_sum);
        }
    }
};

# Time:  O(n)
# Space: O(h)

class Solution(object):
    def convertBST(self, root):
        """
        :type root: TreeNode
        :rtype: TreeNode
        """
        def convertBSTHelper(root, cur_sum):
            if not root:
                return cur_sum

            if root.right:
                cur_sum = convertBSTHelper(root.right, cur_sum)
            cur_sum += root.val
            root.val = cur_sum
            if root.left:
                cur_sum = convertBSTHelper(root.left, cur_sum)
            return cur_sum

        convertBSTHelper(root, 0)
        return root
